1	-------------------------------------------------------------------------------
2	-- Title      : CoaXPress Protocol: http://jiia.org/wp-content/themes/jiia/pdf/standard_dl/coaxpress/CXP-001-2021.pdf
3	-------------------------------------------------------------------------------
4	-- Company    : SLAC National Accelerator Laboratory
5	-------------------------------------------------------------------------------
6	-- Description: CoaXPress Core
7	-------------------------------------------------------------------------------
8	-- This file is part of 'SLAC Firmware Standard Library'.
9	-- It is subject to the license terms in the LICENSE.txt file found in the
10	-- top-level directory of this distribution and at:
11	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
12	-- No part of 'SLAC Firmware Standard Library', including this file,
13	-- may be copied, modified, propagated, or distributed except according to
14	-- the terms contained in the LICENSE.txt file.
15	-------------------------------------------------------------------------------
16	
17	library ieee;
18	use ieee.std_logic_1164.all;
19	
20	library surf;
21	use surf.StdRtlPkg.all;
22	use surf.AxiStreamPkg.all;
23	use surf.AxiLitePkg.all;
24	use surf.CoaXPressPkg.all;
25	
26	entity CoaXPressCore is
27	   generic (
28	      TPD_G              : time                   := 1 ns;
29	      NUM_LANES_G        : positive range 1 to 8  := 1;
30	      STATUS_CNT_WIDTH_G : positive range 1 to 32 := 12;
31	      RX_FSM_CNT_WIDTH_G : positive range 1 to 24 := 16;  -- Optimize this down w.r.t camera to help make timing in CoaXPressRxHsFsm.vhd
32	      AXIL_CLK_FREQ_G    : real                   := 156.25E+6;  -- axilClk frequency (units of Hz)
33	      AXIS_CLK_FREQ_G    : real                   := 156.25E+6;  -- dataClk frequency (units of Hz)
34	      DATA_AXIS_CONFIG_G : AxiStreamConfigType;
35	      CFG_AXIS_CONFIG_G  : AxiStreamConfigType);
36	   port (
37	      gtRstAll        : out sl;
38	      -- Data Interface (dataClk domain)
39	      dataClk         : in  sl;
40	      dataRst         : in  sl;
41	      dataMaster      : out AxiStreamMasterType;
42	      dataSlave       : in  AxiStreamSlaveType;
43	      imageHdrMaster  : out AxiStreamMasterType;
44	      imageHdrSlave   : in  AxiStreamSlaveType;
45	      -- Config Interface (cfgClk domain)
46	      cfgClk          : in  sl;
47	      cfgRst          : in  sl;
48	      cfgIbMaster     : in  AxiStreamMasterType;
49	      cfgIbSlave      : out AxiStreamSlaveType;
50	      cfgObMaster     : out AxiStreamMasterType;
51	      cfgObSlave      : in  AxiStreamSlaveType;
52	      -- Tx Interface (txClk domain)
53	      txClk           : in  sl;
54	      txRst           : in  sl;
55	      txLsValid       : out sl;
56	      txLsData        : out slv(7 downto 0);
57	      txLsDataK       : out sl;
58	      txLsRate        : out sl;
59	      txLsLaneEn      : out slv(3 downto 0);
60	      txTrig          : in  sl;
61	      txLinkUp        : in  sl;
62	      -- Rx Interface (rxClk domain)
63	      rxClk           : in  slv(NUM_LANES_G-1 downto 0);
64	      rxRst           : in  slv(NUM_LANES_G-1 downto 0);
65	      rxData          : in  slv32Array(NUM_LANES_G-1 downto 0);
66	      rxDataK         : in  Slv4Array(NUM_LANES_G-1 downto 0);
67	      rxDispErr       : in  slv(NUM_LANES_G-1 downto 0);
68	      rxDecErr        : in  slv(NUM_LANES_G-1 downto 0);
69	      rxLinkUp        : in  slv(NUM_LANES_G-1 downto 0);
70	      -- AXI-Lite Register Interface (axilClk domain)
71	      axilClk         : in  sl;
72	      axilRst         : in  sl;
73	      axilReadMaster  : in  AxiLiteReadMasterType;
74	      axilReadSlave   : out AxiLiteReadSlaveType;
75	      axilWriteMaster : in  AxiLiteWriteMasterType;
76	      axilWriteSlave  : out AxiLiteWriteSlaveType);
77	end entity CoaXPressCore;
78	
79	architecture mapping of CoaXPressCore is
80	
81	   signal cfgTxMaster : AxiStreamMasterType;
82	   signal cfgTxSlave  : AxiStreamSlaveType;
83	   signal cfgRxMaster : AxiStreamMasterType;
84	
85	   signal configTimerSize : slv(31 downto 0);
86	   signal configErrResp   : sl;
87	   signal configPktTag    : sl;
88	
89	   signal txTrigInv    : sl;
90	   signal txPulseWidth : slv(31 downto 0);
91	   signal swTrig       : sl;
92	   signal txTrigDrop   : sl;
93	
94	   signal eventAck : sl;
95	   signal eventTag : slv(7 downto 0);
96	
97	   signal trigAck     : sl;
98	   signal txLsRateInt : sl;
99	
100	   signal dataMasterInt : AxiStreamMasterType;
101	   signal dataSlaveInt  : AxiStreamSlaveType;
102	
103	   signal rxOverflow     : sl;
104	   signal rxFsmError     : sl;
105	   signal rxFsmRst       : sl;
106	   signal rxNumberOfLane : slv(2 downto 0);
107	
108	begin
109	
110	   txLsRate     <= txLsRateInt;
111	   dataMaster   <= dataMasterInt;
112	   dataSlaveInt <= dataSlave;
113	
114	   U_Config : entity surf.CoaXPressConfig
115	      generic map (
116	         TPD_G         => TPD_G,
117	         AXIS_CONFIG_G => CFG_AXIS_CONFIG_G)
118	      port map (
119	         -- Clock and Reset
120	         cfgClk          => cfgClk,
121	         cfgRst          => cfgRst,
122	         -- Config Interface (cfgClk domain)
123	         configTimerSize => configTimerSize,
124	         configErrResp   => configErrResp,
125	         configPktTag    => configPktTag,
126	         cfgIbMaster     => cfgIbMaster,
127	         cfgIbSlave      => cfgIbSlave,
128	         cfgObMaster     => cfgObMaster,
129	         cfgObSlave      => cfgObSlave,
130	         -- TX Interface
131	         cfgTxMaster     => cfgTxMaster,
132	         cfgTxSlave      => cfgTxSlave,
133	         -- RX Interface
134	         cfgRxMaster     => cfgRxMaster);
135	
136	   U_Tx : entity surf.CoaXPressTx
137	      generic map (
138	         TPD_G => TPD_G)
139	      port map (
140	         -- Config Interface (cfgClk domain)
141	         cfgClk       => cfgClk,
142	         cfgRst       => cfgRst,
143	         cfgTxMaster  => cfgTxMaster,
144	         cfgTxSlave   => cfgTxSlave,
145	         -- Event ACK Interface (cfgClk domain)
146	         eventAck     => eventAck,
147	         eventTag     => eventTag,
148	         -- TX PHY Interface (txClk domain)
149	         txClk        => txClk,
150	         txRst        => txRst,
151	         txLsRate     => txLsRateInt,
152	         txLsValid    => txLsValid,
153	         txLsData     => txLsData,
154	         txLsDataK    => txLsDataK,
155	         -- Trigger Interface (txClk domain)
156	         txTrigInv    => txTrigInv,
157	         txPulseWidth => txPulseWidth,
158	         swTrig       => swTrig,
159	         txTrig       => txTrig,
160	         txTrigDrop   => txTrigDrop);
161	
162	   U_Rx : entity surf.CoaXPressRx
163	      generic map (
164	         TPD_G              => TPD_G,
165	         NUM_LANES_G        => NUM_LANES_G,
166	         RX_FSM_CNT_WIDTH_G => RX_FSM_CNT_WIDTH_G,
167	         AXIS_CONFIG_G      => DATA_AXIS_CONFIG_G)
168	      port map (
169	         -- Data Interface (dataClk domain)
170	         dataClk        => dataClk,
171	         dataRst        => dataRst,
172	         dataMaster     => dataMasterInt,
173	         dataSlave      => dataSlaveInt,
174	         imageHdrMaster => imageHdrMaster,
175	         imageHdrSlave  => imageHdrSlave,
176	         -- Config Interface (cfgClk domain)
177	         cfgClk         => cfgClk,
178	         cfgRst         => cfgRst,
179	         cfgRxMaster    => cfgRxMaster,
180	         -- Event ACK Interface (cfgClk domain)
181	         eventAck       => eventAck,
182	         eventTag       => eventTag,
183	         -- Trigger ACK Interface (txClk domain)
184	         txClk          => txClk,
185	         txRst          => txRst,
186	         trigAck        => trigAck,
187	         -- Rx Interface (rxClk domain)
188	         rxClk          => rxClk,
189	         rxRst          => rxRst,
190	         rxData         => rxData,
191	         rxDataK        => rxDataK,
192	         rxLinkUp       => rxLinkUp,
193	         rxOverflow     => rxOverflow,
194	         rxFsmError     => rxFsmError,
195	         rxFsmRst       => rxFsmRst,
196	         rxNumberOfLane => rxNumberOfLane);
197	
198	   U_Axil : entity surf.CoaXPressAxiL
199	      generic map (
200	         TPD_G              => TPD_G,
201	         NUM_LANES_G        => NUM_LANES_G,
202	         STATUS_CNT_WIDTH_G => STATUS_CNT_WIDTH_G,
203	         RX_FSM_CNT_WIDTH_G => RX_FSM_CNT_WIDTH_G,
204	         AXIL_CLK_FREQ_G    => AXIL_CLK_FREQ_G,
205	         AXIS_CLK_FREQ_G    => AXIS_CLK_FREQ_G,
206	         AXIS_CONFIG_G      => DATA_AXIS_CONFIG_G)
207	      port map (
208	         gtRstAll        => gtRstAll,
209	         -- Tx Interface (txClk domain)
210	         txClk           => txClk,
211	         txRst           => txRst,
212	         txTrigInv       => txTrigInv,
213	         txPulseWidth    => txPulseWidth,
214	         txTrig          => txTrig,
215	         swTrig          => swTrig,
216	         txTrigDrop      => txTrigDrop,
217	         trigAck         => trigAck,
218	         txLinkUp        => txLinkUp,
219	         txLsRate        => txLsRateInt,
220	         txLsLaneEn      => txLsLaneEn,
221	         -- Rx Interface (rxClk domain)
222	         rxClk           => rxClk,
223	         rxRst           => rxRst,
224	         rxDispErr       => rxDispErr,
225	         rxDecErr        => rxDecErr,
226	         rxLinkUp        => rxLinkUp,
227	         rxFsmRst        => rxFsmRst,
228	         rxNumberOfLane  => rxNumberOfLane,
229	         rxOverflow      => rxOverflow,
230	         rxFsmError      => rxFsmError,
231	         -- Config Interface (cfgClk domain)
232	         cfgClk          => cfgClk,
233	         cfgRst          => cfgRst,
234	         configTimerSize => configTimerSize,
235	         configErrResp   => configErrResp,
236	         configPktTag    => configPktTag,
237	         -- Data Interface (dataClk domain)
238	         dataClk         => dataClk,
239	         dataRst         => dataRst,
240	         dataMaster      => dataMasterInt,
241	         dataSlave       => dataSlaveInt,
242	         -- AXI-Lite Register Interface (axilClk domain)
243	         axilClk         => axilClk,
244	         axilRst         => axilRst,
245	         axilReadMaster  => axilReadMaster,
246	         axilReadSlave   => axilReadSlave,
247	         axilWriteMaster => axilWriteMaster,
248	         axilWriteSlave  => axilWriteSlave);
249	
250	end mapping;
251

