1	-------------------------------------------------------------------------------
2	-- Title      : CoaXPress Protocol: http://jiia.org/wp-content/themes/jiia/pdf/standard_dl/coaxpress/CXP-001-2021.pdf
3	-------------------------------------------------------------------------------
4	-- Company    : SLAC National Accelerator Laboratory
5	-------------------------------------------------------------------------------
6	-- Description: CoaXPress RX FSM
7	-------------------------------------------------------------------------------
8	-- This file is part of 'SLAC Firmware Standard Library'.
9	-- It is subject to the license terms in the LICENSE.txt file found in the
10	-- top-level directory of this distribution and at:
11	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
12	-- No part of 'SLAC Firmware Standard Library', including this file,
13	-- may be copied, modified, propagated, or distributed except according to
14	-- the terms contained in the LICENSE.txt file.
15	-------------------------------------------------------------------------------
16	
17	library ieee;
18	use ieee.std_logic_1164.all;
19	use ieee.std_logic_unsigned.all;
20	use ieee.std_logic_arith.all;
21	
22	library surf;
23	use surf.StdRtlPkg.all;
24	use surf.AxiStreamPkg.all;
25	use surf.SsiPkg.all;
26	use surf.CoaXPressPkg.all;
27	
28	entity CoaXPressRxHsFsm is
29	   generic (
30	      TPD_G              : time                   := 1 ns;
31	      RX_FSM_CNT_WIDTH_G : positive range 1 to 24 := 16;  -- Optimize this down w.r.t camera to help make timing in CoaXPressRxHsFsm.vhd
32	      NUM_LANES_G        : positive               := 1);
33	   port (
34	      -- Clock and Reset
35	      rxClk      : in  sl;
36	      rxRst      : in  sl;
37	      -- Config/Status Interface
38	      rxFsmRst   : in  sl;
39	      rxFsmError : out sl;
40	      -- Inbound Stream Interface
41	      rxMaster   : in  AxiStreamMasterType;
42	      rxSlave    : out AxiStreamSlaveType;
43	      -- Outbound Image header Interface
44	      hdrMaster  : out AxiStreamMasterType;
45	      -- Outbound Camera Data Interface
46	      dataMaster : out AxiStreamMasterType);
47	end entity CoaXPressRxHsFsm;
48	
49	architecture rtl of CoaXPressRxHsFsm is
50	
51	   type StateType is (
52	      IDLE_S,
53	      TYPE_S,
54	      HDR_S,
55	      STEP_S,
56	      LINE_S);
57	
58	   type ImageHdrType is record
59	      steamId   : slv(7 downto 0);
60	      sourceTag : slv(15 downto 0);
61	      xSize     : slv(23 downto 0);
62	      xOffs     : slv(23 downto 0);
63	      ySize     : slv(23 downto 0);
64	      yOffs     : slv(23 downto 0);
65	      dsizeL    : slv(23 downto 0);
66	      pixelF    : slv(15 downto 0);
67	      tapG      : slv(15 downto 0);
68	      flags     : slv(7 downto 0);
69	   end record ImageHdrType;
70	   constant IMAGE_HDR_INIT_C : ImageHdrType := (
71	      steamId   => (others => '0'),
72	      sourceTag => (others => '0'),
73	      xSize     => (others => '0'),
74	      xOffs     => (others => '0'),
75	      ySize     => (others => '0'),
76	      yOffs     => (others => '0'),
77	      dsizeL    => (others => '0'),
78	      pixelF    => (others => '0'),
79	      tapG      => (others => '0'),
80	      flags     => (others => '0'));
81	
82	   type DebugType is record
83	      errDet : sl;
84	      maker  : slv(NUM_LANES_G-1 downto 0);
85	      wrd    : natural range 0 to NUM_LANES_G;
86	      cnt    : slv(31 downto 0);
87	   end record DebugType;
88	   constant DEBUG_INIT_C : DebugType := (
89	      errDet => '0',
90	      maker  => (others => '0'),
91	      wrd    => 0,
92	      cnt    => (others => '0'));
93	
94	   subtype LineRemType is natural range 0 to NUM_LANES_G+1;
95	
96	   type RegType is record
97	      endOfLine   : sl;
98	      hdrValid    : sl;
99	      yCnt        : slv(RX_FSM_CNT_WIDTH_G-1 downto 0);
100	      dCnt        : slv(RX_FSM_CNT_WIDTH_G-1 downto 0);
101	      lineRem     : LineRemType;
102	      hdrCnt      : natural range 0 to 25;
103	      hdr         : ImageHdrType;
104	      dbg         : DebugType;
105	      wrd         : natural range 0 to NUM_LANES_G-1;
106	      hdrMaster   : AxiStreamMasterType;
107	      rxSlave     : AxiStreamSlaveType;
108	      dataMasters : AxiStreamMasterArray(1 downto 0);
109	      state       : StateType;
110	   end record RegType;
111	   constant REG_INIT_C : RegType := (
112	      endOfLine   => '0',
113	      hdrValid    => '0',
114	      yCnt        => (others => '0'),
115	      dCnt        => (others => '0'),
116	      lineRem     => 0,
117	      hdrCnt      => 0,
118	      hdr         => IMAGE_HDR_INIT_C,
119	      dbg         => DEBUG_INIT_C,
120	      wrd         => 0,
121	      hdrMaster   => AXI_STREAM_MASTER_INIT_C,
122	      rxSlave     => AXI_STREAM_SLAVE_FORCE_C,
123	      dataMasters => (others => AXI_STREAM_MASTER_INIT_C),
124	      state       => IDLE_S);
125	
126	   signal r       : RegType := REG_INIT_C;
127	   signal rin     : RegType;
128	   signal packRst : sl;
129	
130	   signal pipeMaster : AxiStreamMasterType;
131	   signal pipeSlave  : AxiStreamSlaveType;
132	
133	   -- attribute dont_touch      : string;
134	   -- attribute dont_touch of r : signal is "TRUE";
135	
136	begin
137	
138	   packRst <= rxRst or rxFsmRst;
139	
140	   comb : process (pipeMaster, r, rxFsmRst, rxRst) is
141	      variable v       : RegType;
142	      variable tData   : slv(31 downto 0);
143	      variable eolBeat : sl;
144	      variable eolWrd  : natural range 0 to NUM_LANES_G-1;
145	      variable wordCnt : natural range 0 to NUM_LANES_G;
146	      variable remCnt  : slv(RX_FSM_CNT_WIDTH_G-1 downto 0);
147	   begin
148	      -- Latch the current value
149	      v := r;
150	
151	      -- Init Variable
152	      tData := pipeMaster.tData(32*r.wrd+31 downto 32*r.wrd);
153	
154	      -- Reset strobes
155	      v.dbg.errDet := '0';
156	      v.dbg.maker  := (others => '0');
157	
158	      -- Loop the number of 32-bit words
159	      for i in 0 to NUM_LANES_G-1 loop
160	         -- Check for maker pattern
161	         if (pipeMaster.tData(32*i+31 downto 32*i) = CXP_MARKER_C) then
162	            v.dbg.maker(i) := '1';
163	         end if;
164	      end loop;
165	
166	      -- Init header stream
167	      v.hdrMaster.tValid           := '0';  -- Reset strobe
168	      v.hdrMaster.tLast            := '1';  -- single word write
169	      v.hdrMaster.tUser(SSI_SOF_C) := '1';  -- single word write
170	
171	      -- Init data stream
172	      v.dataMasters(0).tValid := '0';                -- Reset strobe
173	      v.dataMasters(0).tData  := pipeMaster.tData;
174	      -- Check if state is not STEP_S
175	      if (r.state /= STEP_S) then
176	         v.dataMasters(0).tKeep := (others => '0');  -- Reset bus
177	      end if;
178	
179	      -- Flow Control
180	      v.rxSlave.tReady := '0';
181	
182	      -- Check for valid data
183	      if (pipeMaster.tValid = '1') then
184	
185	         -- State Machine
186	         case r.state is
187	            ----------------------------------------------------------------------
188	            when IDLE_S =>
189	               -- Reset counter
190	               v.dCnt := (others => '0');
191	
192	               -- Check for the marker
193	               if (tData = CXP_MARKER_C) then
194	                  -- Next State
195	                  v.state := TYPE_S;
196	
197	               else
198	                  -- Set the flag
199	                  v.dbg.errDet := '1';
200	               end if;
201	            ----------------------------------------------------------------------
202	            when TYPE_S =>
203	               -- Check for "Rectangular image header indication"
204	               if (tData = x"01_01_01_01") then
205	
206	                  -- Preset counter
207	                  v.hdrCnt := 3;
208	
209	                  -- Reset counters
210	                  v.endOfLine := '0';
211	                  v.hdrValid  := '0';
212	                  v.yCnt      := (others => '0');
213	
214	                  -- Check for out of sync header
215	                  if (r.hdrValid = '1') and (r.yCnt /= r.hdr.ySize(RX_FSM_CNT_WIDTH_G-1 downto 0)) then
216	                     -- Set the flag
217	                     v.dbg.errDet := '1';
218	                  end if;
219	
220	                  -- Next State
221	                  v.state := HDR_S;
222	
223	               -- Check for "Rectangular line marker"
224	               elsif (tData = x"02_02_02_02") then
225	                  if (r.hdrValid = '1') then
226	                     -- Next State
227	                     v.state := LINE_S;
228	                  else
229	                     -- Set the flag
230	                     v.dbg.errDet := '1';
231	
232	                     -- Next State
233	                     v.state := IDLE_S;
234	                  end if;
235	
236	               else
237	                  -- Set the flag
238	                  v.dbg.errDet := '1';
239	
240	                  -- Next State
241	                  v.state := IDLE_S;
242	               end if;
243	            ----------------------------------------------------------------------
244	            when HDR_S =>
245	               if (tData(7 downto 0) /= tData(15 downto 8))
246	                  or (tData(7 downto 0) /= tData(23 downto 16))
247	                  or (tData(7 downto 0) /= tData(31 downto 24)) then
248	
249	                  -- Reset counter
250	                  v.endOfLine := '0';
251	                  v.hdrCnt    := 0;
252	                  v.hdrValid  := '0';
253	
254	                  -- Set the flag
255	                  v.dbg.errDet := '1';
256	
257	                  -- Next State
258	                  v.state := IDLE_S;
259	
260	               -- Check for roll over
261	               elsif (r.hdrCnt = 25) then
262	
263	                  -- Reset counter
264	                  v.hdrCnt   := 0;
265	                  v.hdrValid := '1';
266	
267	                  -- Forward the image header
268	                  v.hdrMaster.tValid := '1';
269	
270	                  -- Next State
271	                  v.state := IDLE_S;
272	
273	               else
274	                  -- Increment the counter
275	                  v.hdrCnt := r.hdrCnt + 1;
276	               end if;
277	            ----------------------------------------------------------------------
278	            when STEP_S =>
279	               -- Map the TKEEP word
280	               v.dataMasters(0).tKeep(4*r.wrd+3 downto 4*r.wrd) := x"F";
281	
282	               -- Increment the counter
283	               v.dCnt := r.dCnt + 1;
284	
285	               -- Check for max count
286	               if (r.lineRem = 1) then
287	
288	                  -- Move the data
289	                  v.dataMasters(0).tValid := '1';
290	
291	                  -- Set the "end of line" flag
292	                  v.endOfLine := '1';
293	
294	                  -- Next State
295	                  v.state := IDLE_S;
296	
297	               end if;
298	            ----------------------------------------------------------------------
299	            when LINE_S =>
300	               -- Write the data
301	               v.dataMasters(0).tValid := '1';
302	
303	               -- Accept the data unless the next word in this same beat must be
304	               -- reparsed as the next marker/type sequence.
305	               v.rxSlave.tReady := '1';
306	               eolBeat          := '0';
307	               eolWrd           := 0;
308	               wordCnt          := 0;
309	
310	               -- Loop the number of 32-bit words
311	               for i in 0 to NUM_LANES_G-1 loop
312	
313	                  -- Check for valid data
314	                  if (pipeMaster.tKeep(4*i) = '1') then
315	                     wordCnt := wordCnt + 1;
316	
317	                     -- Check for not "end of line"
318	                     if (wordCnt <= r.lineRem) then
319	
320	                        -- Update the TKEEP mask
321	                        v.dataMasters(0).tKeep(4*i+3 downto 4*i) := x"F";
322	
323	                        -- Increment the counter
324	                        v.dCnt := v.dCnt + 1;
325	
326	                     end if;
327	
328	                     -- Check for max count
329	                     if (wordCnt = r.lineRem) then
330	
331	                        -- Flag the end of line word in this beat
332	                        eolBeat := '1';
333	                        eolWrd  := i;
334	
335	                        -- Set the "end of line" flag
336	                        v.endOfLine := '1';
337	
338	                        -- Next State
339	                        v.state := IDLE_S;
340	
341	                     end if;
342	
343	                  end if;
344	
345	               end loop;
346	
347	               if (eolBeat = '1') and (eolWrd /= NUM_LANES_G-1) then
348	                  if (pipeMaster.tKeep(4*(eolWrd+1)) = '1') then
349	                     v.rxSlave.tReady := '0';
350	                     v.wrd            := eolWrd+1;
351	                  else
352	                     v.wrd := 0;
353	                  end if;
354	               elsif (eolBeat = '1') then
355	                  v.wrd := 0;
356	               end if;
357	         ----------------------------------------------------------------------
358	         end case;
359	
360	         -- Check if current state is not LINE_S
361	         if (r.state /= LINE_S) then
362	
363	            -- Check for roll over
364	            if (r.wrd = NUM_LANES_G-1) then
365	               -- Reset the counter
366	               v.wrd := 0;
367	
368	               -- Accept the data
369	               v.rxSlave.tReady := '1';
370	
371	            else
372	               -- Increment the counter
373	               v.wrd := r.wrd + 1;
374	
375	               -- Check if no more data available
376	               if (pipeMaster.tKeep(4*v.wrd) = '0') then
377	                  -- Reset the counter
378	                  v.wrd := 0;
379	
380	                  -- Accept the data
381	                  v.rxSlave.tReady := '1';
382	
383	               end if;
384	
385	            end if;
386	
387	            -- Check if next state is LINE_S but not aligned
388	            if (v.state = LINE_S) and (v.wrd /= 0) then
389	               -- Switch to stepping state
390	               v.state := STEP_S;
391	
392	            end if;
393	
394	            -- Check for STEP_S state
395	            if (r.state = STEP_S) and (v.state = STEP_S) and (v.rxSlave.tReady = '1') then
396	               -- Move the data
397	               v.dataMasters(0).tValid := '1';
398	
399	               -- Switch to bursting state
400	               v.state := LINE_S;
401	
402	            end if;
403	
404	         end if;
405	
406	      end if;
407	
408	      -- Shift the pipeline and convert tKEEP to count (helps with making timing in byte packer)
409	      v.dataMasters(1) := r.dataMasters(0);
410	
411	      -- Check for end of line in the previous cycle
412	      if (r.endOfLine = '1') then
413	
414	         -- Reset flag
415	         v.endOfLine := '0';
416	
417	         -- Increment counter
418	         v.yCnt := v.yCnt + 1;
419	
420	         -- Check for max count
421	         if (v.yCnt = r.hdr.ySize(RX_FSM_CNT_WIDTH_G-1 downto 0)) then
422	            -- Terminate the frame
423	            v.dataMasters(1).tLast := '1';
424	         end if;
425	
426	      end if;
427	
428	      -- Debugging: tracking the number of words
429	      v.dbg.wrd := 0;
430	      for i in 0 to NUM_LANES_G-1 loop
431	         if (r.dataMasters(1).tValid = '1') and (r.dataMasters(1).tKeep(4*i) = '1') then
432	            v.dbg.wrd := v.dbg.wrd + 1;
433	         end if;
434	      end loop;
435	      if (r.state = HDR_S) then
436	         -- Reset counter
437	         v.dbg.cnt := (others => '0');
438	      else
439	         -- Increment counter
440	         v.dbg.cnt := r.dbg.cnt + r.dbg.wrd;
441	      end if;
442	
443	      -- Update header based on counter
444	      case r.hdrCnt is
445	         ----------------------------------------------------------------
446	         when 3  => v.hdr.steamId(7 downto 0)    := tData(7 downto 0);
447	         ----------------------------------------------------------------
448	         when 4  => v.hdr.sourceTag(15 downto 8) := tData(7 downto 0);
449	         when 5  => v.hdr.sourceTag(7 downto 0)  := tData(7 downto 0);
450	         ----------------------------------------------------------------
451	         when 6  => v.hdr.xSize(23 downto 16)    := tData(7 downto 0);
452	         when 7  => v.hdr.xSize(15 downto 8)     := tData(7 downto 0);
453	         when 8  => v.hdr.xSize(7 downto 0)      := tData(7 downto 0);
454	         ----------------------------------------------------------------
455	         when 9  => v.hdr.xOffs(23 downto 16)    := tData(7 downto 0);
456	         when 10 => v.hdr.xOffs(15 downto 8)     := tData(7 downto 0);
457	         when 11 => v.hdr.xOffs(7 downto 0)      := tData(7 downto 0);
458	         ----------------------------------------------------------------
459	         when 12 => v.hdr.ySize(23 downto 16)    := tData(7 downto 0);
460	         when 13 => v.hdr.ySize(15 downto 8)     := tData(7 downto 0);
461	         when 14 => v.hdr.ySize(7 downto 0)      := tData(7 downto 0);
462	         ----------------------------------------------------------------
463	         when 15 => v.hdr.yOffs(23 downto 16)    := tData(7 downto 0);
464	         when 16 => v.hdr.yOffs(15 downto 8)     := tData(7 downto 0);
465	         when 17 => v.hdr.yOffs(7 downto 0)      := tData(7 downto 0);
466	         ----------------------------------------------------------------
467	         when 18 => v.hdr.dsizeL(23 downto 16)   := tData(7 downto 0);
468	         when 19 => v.hdr.dsizeL(15 downto 8)    := tData(7 downto 0);
469	         when 20 => v.hdr.dsizeL(7 downto 0)     := tData(7 downto 0);
470	         ----------------------------------------------------------------
471	         when 21 => v.hdr.pixelF(15 downto 8)    := tData(7 downto 0);
472	         when 22 => v.hdr.pixelF(7 downto 0)     := tData(7 downto 0);
473	         ----------------------------------------------------------------
474	         when 23 => v.hdr.tapG(15 downto 8)      := tData(7 downto 0);
475	         when 24 => v.hdr.tapG(7 downto 0)       := tData(7 downto 0);
476	         ----------------------------------------------------------------
477	         when 25 => v.hdr.flags(7 downto 0)      := tData(7 downto 0);
478	         ----------------------------------------------------------------
479	         when others =>
480	            null;
481	      end case;
482	
483	      -- Register a small saturated remaining-word count.  This breaks the wide
484	      -- dCnt-to-wrd path when a line ends mid-beat and the next marker is held
485	      -- in the current input word.
486	      if (v.dCnt >= v.hdr.dsizeL(RX_FSM_CNT_WIDTH_G-1 downto 0)) then
487	         v.lineRem := 0;
488	      else
489	         remCnt := v.hdr.dsizeL(RX_FSM_CNT_WIDTH_G-1 downto 0) - v.dCnt;
490	         if (conv_integer(remCnt) > NUM_LANES_G) then
491	            v.lineRem := NUM_LANES_G+1;
492	         else
493	            v.lineRem := conv_integer(remCnt);
494	         end if;
495	      end if;
496	
497	      -----------------------------------------------------------------------------
498	      -- Perform an endianness swap in header message and remove redundant bytes --
499	      -----------------------------------------------------------------------------
500	      --                This is the image header format                          --
501	      -----------------------------------------------------------------------------
502	      -- WORD[0]BIT[31:0]
503	      v.hdrMaster.tData(7 downto 0)   := r.hdr.steamId(7 downto 0);
504	      v.hdrMaster.tData(15 downto 8)  := v.hdr.flags(7 downto 0);  -- variable (not reg) because same cycle as (r.hdrCnt = 25)
505	      v.hdrMaster.tData(31 downto 16) := r.hdr.sourceTag(15 downto 0);
506	
507	      -- WORD[1]BIT[31:0]
508	      v.hdrMaster.tData(63 downto 32) := x"00" & r.hdr.xSize(23 downto 0);
509	
510	      -- WORD[2]BIT[31:0]
511	      v.hdrMaster.tData(95 downto 64) := x"00" & r.hdr.xOffs(23 downto 0);
512	
513	      -- WORD[3]BIT[31:0]
514	      v.hdrMaster.tData(127 downto 96) := x"00" & r.hdr.ySize(23 downto 0);
515	
516	      -- WORD[4]BIT[31:0]
517	      v.hdrMaster.tData(159 downto 128) := x"00" & r.hdr.yOffs(23 downto 0);
518	
519	      -- WORD[5]BIT[31:0]
520	      v.hdrMaster.tData(191 downto 160) := x"00" & r.hdr.dsizeL(23 downto 0);
521	
522	      -- WORD[6]BIT[31:0]
523	      v.hdrMaster.tData(207 downto 192) := r.hdr.pixelF(15 downto 0);
524	      v.hdrMaster.tData(223 downto 208) := r.hdr.tapG(15 downto 0);
525	
526	      -- Outputs
527	      pipeSlave  <= v.rxSlave;
528	      hdrMaster  <= r.hdrMaster;
529	      rxFsmError <= r.dbg.errDet;
530	
531	      -- Reset
532	      if (rxRst = '1') or (rxFsmRst = '1') then
533	         v := REG_INIT_C;
534	      end if;
535	
536	      -- Register the variable for next clock cycle
537	      rin <= v;
538	
539	   end process comb;
540	
541	   seq : process (rxClk) is
542	   begin
543	      if (rising_edge(rxClk)) then
544	         r <= rin after TPD_G;
545	      end if;
546	   end process seq;
547	
548	   U_RxPipe : entity surf.AxiStreamPipeline
549	      generic map (
550	         TPD_G         => TPD_G,
551	         PIPE_STAGES_G => 1)
552	      port map (
553	         axisClk     => rxClk,
554	         axisRst     => packRst,
555	         sAxisMaster => rxMaster,
556	         sAxisSlave  => rxSlave,
557	         mAxisMaster => pipeMaster,
558	         mAxisSlave  => pipeSlave);
559	
560	   U_Pack : entity surf.CoaXPressRxWordPacker
561	      generic map (
562	         TPD_G       => TPD_G,
563	         NUM_LANES_G => NUM_LANES_G)
564	      port map (
565	         rxClk       => rxClk,
566	         rxRst       => packRst,
567	         sAxisMaster => r.dataMasters(1),
568	         mAxisMaster => dataMaster);
569	
570	end rtl;
571

