1	-------------------------------------------------------------------------------
2	-- Title      : CoaXPress Protocol: http://jiia.org/wp-content/themes/jiia/pdf/standard_dl/coaxpress/CXP-001-2021.pdf
3	-------------------------------------------------------------------------------
4	-- Company    : SLAC National Accelerator Laboratory
5	-------------------------------------------------------------------------------
6	-- Description: CoaXPress TX Low Speed FSM
7	-------------------------------------------------------------------------------
8	-- This file is part of 'SLAC Firmware Standard Library'.
9	-- It is subject to the license terms in the LICENSE.txt file found in the
10	-- top-level directory of this distribution and at:
11	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
12	-- No part of 'SLAC Firmware Standard Library', including this file,
13	-- may be copied, modified, propagated, or distributed except according to
14	-- the terms contained in the LICENSE.txt file.
15	-------------------------------------------------------------------------------
16	
17	library ieee;
18	use ieee.std_logic_1164.all;
19	use ieee.std_logic_unsigned.all;
20	use ieee.std_logic_arith.all;
21	
22	library surf;
23	use surf.StdRtlPkg.all;
24	use surf.AxiStreamPkg.all;
25	use surf.SsiPkg.all;
26	use surf.CoaXPressPkg.all;
27	use surf.Code8b10bPkg.all;
28	
29	entity CoaXPressTxLsFsm is
30	   generic (
31	      TPD_G : time := 1 ns);
32	   port (
33	      -- Clock and Reset
34	      txClk        : in  sl;            -- 312.5 MHz clock
35	      txRst        : in  sl;
36	      -- Config Interface
37	      cfgMaster    : in  AxiStreamMasterType;
38	      cfgSlave     : out AxiStreamSlaveType;
39	      -- Trigger Interface
40	      txTrig       : in  sl;
41	      txTrigInv    : in  sl;
42	      txPulseWidth : in  slv(31 downto 0);
43	      txTrigDrop   : out sl;
44	      -- TX PHY Interface
45	      txRate       : in  sl;
46	      txStrobe     : out sl;
47	      txData       : out slv(7 downto 0);
48	      txDataK      : out sl);
49	end entity CoaXPressTxLsFsm;
50	
51	architecture rtl of CoaXPressTxLsFsm is
52	
53	   function genTxDly return Slv8Array is
54	      variable retVar : Slv8Array(149 downto 0);
55	      variable i      : natural;
56	   begin
57	      for i in 0 to 149 loop
58	         retVar(i) := toSlv(getTimeRatio(i*(240.0/150.0), 1.0), 8);
59	      end loop;
60	      return retVar;
61	   end function;
62	
63	   constant CXP_TRIG_K_C : slv(5 downto 0)         := "000111";
64	   constant TX_DLY_C     : Slv8Array(149 downto 0) := genTxDly;
65	
66	   type RegType is record
67	      -- Heartbeat
68	      heartbeat      : sl;
69	      heartbeatCnt   : slv(7 downto 0);
70	      -- Trigger
71	      txTrig         : sl;
72	      txTrigDrop     : sl;
73	      txTrigCnt      : natural range 0 to 6;
74	      txTrigData     : Slv8Array(5 downto 0);
75	      txPulseWidth   : slv(31 downto 0);
76	      txTrigWidthCnt : slv(31 downto 0);
77	      -- IDLE
78	      txIdle         : sl;
79	      txIdleCnt      : natural range 0 to 4;
80	      -- TX PHY
81	      txStrobe       : sl;
82	      txData         : slv(7 downto 0);
83	      txDataK        : sl;
84	      -- Config
85	      cfgSlave       : AxiStreamSlaveType;
86	   end record RegType;
87	
88	   constant REG_INIT_C : RegType := (
89	      -- Heartbeat
90	      heartbeat      => '0',
91	      heartbeatCnt   => (others => '0'),
92	      -- Trigger
93	      txTrig         => '0',
94	      txTrigDrop     => '0',
95	      txTrigCnt      => 6,
96	      txTrigData     => (0 => K_28_2_C, 1 => K_28_4_C, 2 => K_28_4_C, 3 => x"00", 4 => x"00", 5 => x"00"),
97	      txPulseWidth   => (others => '0'),
98	      txTrigWidthCnt => (others => '0'),
99	      -- IDLE
100	      txIdle         => '1',
101	      txIdleCnt      => 4,
102	      -- TX PHY
103	      txStrobe       => '0',
104	      txData         => K_28_5_C,
105	      txDataK        => '1',
106	      -- Config
107	      cfgSlave       => AXI_STREAM_SLAVE_INIT_C);
108	
109	   signal r   : RegType := REG_INIT_C;
110	   signal rin : RegType;
111	
112	   attribute rom_style               : string;
113	   attribute rom_style of TX_DLY_C   : constant is "distributed";
114	   attribute rom_extract             : string;
115	   attribute rom_extract of TX_DLY_C : constant is "TRUE";
116	   attribute syn_keep                : string;
117	   attribute syn_keep of TX_DLY_C    : constant is "TRUE";
118	
119	   -- attribute dont_touch      : string;
120	   -- attribute dont_touch of r : signal is "TRUE";
121	
122	begin
123	
124	   comb : process (cfgMaster, r, txPulseWidth, txRate, txRst, txTrig,
125	                   txTrigInv) is
126	      variable v   : RegType;
127	      variable idx : natural;
128	   begin
129	      -- Latch the current value
130	      v := r;
131	
132	      -- Reset strobes
133	      v.heartbeat  := '0';
134	      v.txStrobe   := '0';
135	      v.txTrigDrop := '0';
136	      v.cfgSlave   := AXI_STREAM_SLAVE_INIT_C;
137	
138	      -- Check for heartbeat event
139	      if (r.heartbeatCnt = 0) then
140	
141	         -- txRate=0: 20.83 Mbps (48ns UI)
142	         if (txRate = '0') then
143	
144	            -- 149 = (10b x 312.5MHz / 20.833333Mbps)-1
145	            v.heartbeatCnt := toSlv(149, 8);
146	
147	         else
148	            -- 74 = (10b x 312.5MHz / 41.666666Mbps)-1
149	            v.heartbeatCnt := toSlv(74, 8);
150	
151	         end if;
152	
153	         -- Set the flag
154	         v.heartbeat := '1';
155	
156	      else
157	         -- Decrement the counter
158	         v.heartbeatCnt := r.heartbeatCnt - 1;
159	      end if;
160	
161	      -- Update trig delay index variable
162	      if (txRate = '0') then
163	         idx := conv_integer(v.heartbeatCnt);
164	      else
165	         idx := 2*conv_integer(v.heartbeatCnt);
166	      end if;
167	
168	      -- Decrement the counter
169	      if (r.txTrigWidthCnt /= 0) then
170	         v.txTrigWidthCnt := r.txTrigWidthCnt - 1;
171	      end if;
172	
173	      -- Check for change in txPulseWidth while making trigger pulse
174	      v.txPulseWidth := txPulseWidth;
175	      if (r.txPulseWidth /= v.txPulseWidth) and (v.txTrigWidthCnt /= 0) then
176	         -- Force the pulse to terminate in next 8 cycles (>6 byte message)
177	         v.txTrigWidthCnt := toSlv(8, 32);
178	      end if;
179	
180	      -- Keep a delayed copy
181	      v.txTrig := txTrig;
182	
183	      -- Check for rising edge or counter timeout
184	      if ((r.txTrig = '0') and (v.txTrig = '1')) or (r.txTrigWidthCnt = 1) then
185	
186	         -- Check if not moving trigger message
187	         if (r.txTrigCnt = 6) then
188	
189	            -- Reset the counter
190	            v.txTrigCnt := 0;
191	
192	            -- Check for rising edge
193	            if (r.txTrig = '0') and (v.txTrig = '1') then
194	
195	               -- Check if inverted trigger
196	               if (txTrigInv = '0') then
197	                  -- Trigger packet indication - LinkTrigger0
198	                  v.txTrigData(0) := K_28_2_C;
199	                  v.txTrigData(1) := K_28_4_C;
200	                  v.txTrigData(2) := K_28_4_C;
201	               else
202	                  -- Trigger packet indication - LinkTrigger1
203	                  v.txTrigData(0) := K_28_4_C;
204	                  v.txTrigData(1) := K_28_2_C;
205	                  v.txTrigData(2) := K_28_2_C;
206	               end if;
207	
208	               -- Start the timer
209	               v.txTrigWidthCnt := r.txPulseWidth;
210	
211	            -- Else counter timeout
212	            else
213	
214	               -- Check if inverted trigger
215	               if (txTrigInv = '0') then
216	                  -- Trigger packet indication - LinkTrigger1
217	                  v.txTrigData(0) := K_28_4_C;
218	                  v.txTrigData(1) := K_28_2_C;
219	                  v.txTrigData(2) := K_28_2_C;
220	               else
221	                  -- Trigger packet indication - LinkTrigger0
222	                  v.txTrigData(0) := K_28_2_C;
223	                  v.txTrigData(1) := K_28_4_C;
224	                  v.txTrigData(2) := K_28_4_C;
225	               end if;
226	
227	            end if;
228	
229	            -- Set the trigger delay
230	            for i in 3 to 5 loop
231	               v.txTrigData(i) := TX_DLY_C(149-idx);
232	            end loop;
233	
234	         else
235	            -- Set the flag
236	            v.txTrigDrop := '1';
237	         end if;
238	
239	      end if;
240	
241	      -- Check for heartbeat
242	      if (r.heartbeat = '1') then
243	
244	         -- Update the strobe
245	         v.txStrobe := '1';
246	
247	         -- Check if moving trigger message
248	         if (r.txTrigCnt /= 6) then
249	
250	            -- Increment the counter
251	            v.txTrigCnt := r.txTrigCnt + 1;
252	
253	            -- Update the TX data
254	            v.txData  := r.txTrigData(r.txTrigCnt);
255	            v.txDataK := CXP_TRIG_K_C(r.txTrigCnt);
256	
257	         -- Check if moving idle message
258	         elsif (r.txIdleCnt /= 4) then
259	
260	            -- Increment the counter
261	            v.txIdleCnt := r.txIdleCnt + 1;
262	
263	            -- Update the TX data
264	            v.txData  := CXP_TX_IDLE_C(r.txIdleCnt);
265	            v.txDataK := CXP_IDLE_K_C(r.txIdleCnt);
266	
267	         -- Check if moving config message
268	         elsif (cfgMaster.tValid = '1') and (r.txIdle = '0') then
269	
270	            -- Accept the data
271	            v.cfgSlave.tReady := '1';
272	
273	            -- Send the configuration message
274	            v.txData  := cfgMaster.tData(7 downto 0);
275	            v.txDataK := cfgMaster.tUser(0);
276	
277	         -- Insert the IDLE
278	         else
279	
280	            -- Reset flag
281	            v.txIdle := '0';
282	
283	            -- Preset the counter
284	            v.txIdleCnt := 1;
285	
286	            -- Update the TX data
287	            v.txData  := CXP_TX_IDLE_C(0);
288	            v.txDataK := CXP_IDLE_K_C(0);
289	
290	         end if;
291	
292	      end if;
293	
294	      -- Outputs
295	      cfgSlave   <= v.cfgSlave;
296	      txStrobe   <= r.txStrobe;
297	      txData     <= r.txData;
298	      txDataK    <= r.txDataK;
299	      txTrigDrop <= r.txTrigDrop;
300	
301	      -- Reset
302	      if (txRst = '1') then
303	         v := REG_INIT_C;
304	      end if;
305	
306	      -- Register the variable for next clock cycle
307	      rin <= v;
308	
309	   end process comb;
310	
311	   seq : process (txClk) is
312	   begin
313	      if (rising_edge(txClk)) then
314	         r <= rin after TPD_G;
315	      end if;
316	   end process seq;
317	
318	end rtl;
