-------------------------------------------------------------------------------
-- Title      : CXP Over Fiber Protocol: http://jiia.org/wp-content/themes/jiia/pdf/standard_dl/coaxpress/CXPR-008-2021.pdf
-------------------------------------------------------------------------------
-- Company    : SLAC National Accelerator Laboratory
-------------------------------------------------------------------------------
-- Description: CoaXPress Over Fiber TX Bridge
-------------------------------------------------------------------------------
-- This file is part of 'SLAC Firmware Standard Library'.
-- It is subject to the license terms in the LICENSE.txt file found in the
-- top-level directory of this distribution and at:
--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
-- No part of 'SLAC Firmware Standard Library', including this file,
-- may be copied, modified, propagated, or distributed except according to
-- the terms contained in the LICENSE.txt file.
-------------------------------------------------------------------------------

library ieee;
use ieee.std_logic_1164.all;
use ieee.std_logic_unsigned.all;
use ieee.std_logic_arith.all;

library surf;
use surf.StdRtlPkg.all;
use surf.CoaXPressPkg.all;

entity CoaXPressOverFiberBridgeTx is
   generic (
      TPD_G : time := 1 ns);
   port (
      -- Clock and Reset
      clk        : in  sl;
      rst        : in  sl;
      -- XGMII interface
      xgmiiTxd   : out slv(31 downto 0);
      xgmiiTxc   : out slv(3 downto 0);
      -- TX PHY Interface
      txLsValid  : in  sl;
      txLsData   : in  slv(7 downto 0);
      txLsDataK  : in  sl;
      txLsRate   : in  sl;
      txLsLaneEn : in  slv(3 downto 0));
end entity CoaXPressOverFiberBridgeTx;

architecture rtl of CoaXPressOverFiberBridgeTx is

   type StateType is (
      IDLE_S,
      LS_SOP_S,
      LS_PAYLOAD_S);

   type RegType is record
      update    : sl;
      cnt       : natural range 0 to 3;
      idle      : natural range 0 to 3;
      txLsRate  : sl;
      txLsData  : slv(7 downto 0);
      txLsDataK : sl;
      xgmiiTxd  : slv(31 downto 0);
      xgmiiTxc  : slv(3 downto 0);
      state     : StateType;
   end record RegType;

   constant REG_INIT_C : RegType := (
      update    => '1',
      cnt       => 0,
      idle      => 0,
      txLsRate  => '0',
      txLsData  => (others => '0'),
      txLsDataK => '0',
      xgmiiTxd  => CXPOF_IDLE_WORD_C,
      xgmiiTxc  => x"F",
      state     => IDLE_S);

   signal r   : RegType := REG_INIT_C;
   signal rin : RegType;

   -- attribute dont_touch      : string;
   -- attribute dont_touch of r : signal is "TRUE";

begin

   comb : process (r, rst, txLsData, txLsDataK, txLsLaneEn, txLsRate,
                   txLsValid) is
      variable v : RegType;
   begin
      -- Latch the current value
      v := r;

      -- Check for change in low speed rate
      v.txLsRate := txLsRate;
      if (r.txLsRate /= v.txLsRate) then
         v.update := '1';
      end if;

      -- State Machine
      case r.state is
         ----------------------------------------------------------------------
         when IDLE_S =>
            -- Send the start word
            v.xgmiiTxc := x"F";
            v.xgmiiTxd := CXPOF_IDLE_WORD_C;

            -- Check for new low speed byte
            if (txLsValid = '1') then
               -- Save copy of data
               v.txLsData  := txLsData;
               v.txLsDataK := txLsDataK;
               -- Next State
               v.state     := LS_SOP_S;
            end if;
         ----------------------------------------------------------------------
         when LS_SOP_S =>
            -- Set the char marker
            v.xgmiiTxc := "0001";

            -- Lane[0] = Start[7:0]
            v.xgmiiTxd(0+7 downto 0+0) := CXPOF_START_C;

            -- Reset the flag
            v.update := '0';

            -- Lane[1] = SopCtrl[7] - Packet type: "0" => Low-speed packet
            v.xgmiiTxd(8+7) := '0';

            -- Lane[1] = SopCtrl[6:4] - Reserved
            v.xgmiiTxd(8+6 downto 8+4) := "000";

            -- Lane[1] = SopCtrl[3] - Update flag
            v.xgmiiTxd(8+3) := r.update;

            -- Lane[1] = SopCtrl[2] - Reserved
            v.xgmiiTxd(8+2) := '0';

            -- Lane[1] = SopCtrl[1] - Low-speed rate: When '0'=> 20.83 Mbps, When '1'=> 41.6 Mbps
            v.xgmiiTxd(8+1) := r.txLsRate;

            -- Lane[1] = SopCtrl[0] - High-speed upconnection state
            v.xgmiiTxd(8+0) := '0';

            -- Lane[2] = SopData0[7:0] - reserved
            v.xgmiiTxd(16+7 downto 16+0) := x"00";

            -- Lane[3] = SopData1[7:0] - reserved
            v.xgmiiTxd(24+7 downto 24+0) := x"00";

            -- Next State
            v.state := LS_PAYLOAD_S;
         ----------------------------------------------------------------------
         when LS_PAYLOAD_S =>
            -- Increment the counter
            v.cnt := r.cnt + 1;

            -- Reset the data and char bus
            v.xgmiiTxc := (others => '0');
            v.xgmiiTxd := (others => '0');

            -- Check for LS Stream
            if (r.cnt < 2) then

               -- Loop through the channels
               for i in 0 to 1 loop

                  -- Check if LS Stream is enabled
                  if (txLsLaneEn(2*r.cnt+i) = '1') then

                     -- LS CTRL
                     if (r.txLsDataK = '0') then
                        v.xgmiiTxd(16*i+7 downto 16*i) := x"01";  -- data
                     else
                        v.xgmiiTxd(16*i+7 downto 16*i) := x"02";  -- k-code
                     end if;

                     -- LS Char
                     v.xgmiiTxd(16*i+15 downto 16*i+8) := r.txLsData;

                  -- Else send IDLE
                  else

                     -- LS CTRL
                     if (CXP_IDLE_K_C(r.idle) = '0') then
                        v.xgmiiTxd(16*i+7 downto 16*i) := x"01";  -- data
                     else
                        v.xgmiiTxd(16*i+7 downto 16*i) := x"02";  -- k-code
                     end if;

                     -- LS Char
                     v.xgmiiTxd(16*i+15 downto 16*i+8) := CXP_TX_IDLE_C(r.idle);

                  end if;

               end loop;

            else
               -- Reset the counter
               v.cnt := 0;

               -- Set the char marker
               v.xgmiiTxc := "1100";

               -- Lane[0] = Reserved
               v.xgmiiTxd(7 downto 0) := x"00";

               -- Lane[1] = Reserved
               v.xgmiiTxd(15 downto 8) := x"00";

               -- Lane[2] = Terminate
               v.xgmiiTxd(23 downto 16) := CXPOF_TERM_C;

               -- Lane[3] = Terminate
               v.xgmiiTxd(31 downto 24) := CXPOF_IDLE_C;

               -- Check non-enabled IDLE index
               if (r.idle = 3) then
                  -- Reset the counter
                  v.idle := 0;
               else
                  -- Increment the counter
                  v.idle := r.idle + 1;
               end if;

               -- Next State
               v.state := IDLE_S;

            end if;
      ----------------------------------------------------------------------
      end case;

      -- Outputs
      xgmiiTxd <= r.xgmiiTxd;
      xgmiiTxc <= r.xgmiiTxc;

      -- Reset
      if (rst = '1') then
         v := REG_INIT_C;
      end if;

      -- Register the variable for next clock cycle
      rin <= v;

   end process comb;

   seq : process (clk) is
   begin
      if (rising_edge(clk)) then
         r <= rin after TPD_G;
      end if;
   end process seq;

end rtl;

# Load RUCKUS library
source $::env(RUCKUS_PROC_TCL)

# Load the Core
loadRuckusTcl "$::DIR_PATH/core"

# Get the family type
set family [getFpgaArch]

if { ${family} eq {kintexu} ||
     ${family} eq {virtexu} } {
   loadRuckusTcl "$::DIR_PATH/gthUs"
}

if { ${family} eq {kintexuplus} ||
     ${family} eq {zynquplus} ||
     ${family} eq {zynquplusRFSOC} } {
   loadRuckusTcl "$::DIR_PATH/gthUs+"
   loadRuckusTcl "$::DIR_PATH/gtyUs+"
}

if { ${family} eq {virtexuplus} ||
     ${family} eq {virtexuplusHBM} } {
   loadRuckusTcl "$::DIR_PATH/gtyUs+"
}

# Load RUCKUS library
source $::env(RUCKUS_PROC_TCL)

# Load Source Code
if { $::env(VIVADO_VERSION) >= 2021.2 } {

   # Load Source Code
   loadSource -lib surf -dir "$::DIR_PATH/rtl"

   loadSource -path "$::DIR_PATH/ip/CoaXPressOverFiberGthUsIp.dcp"
   # loadIpCore -path "$::DIR_PATH/ip/CoaXPressOverFiberGthUsIp.xci"

} else {
   puts "\n\nWARNING: $::DIR_PATH requires Vivado 2021.2 (or later)\n\n"
}

-------------------------------------------------------------------------------
-- Title      : CoaXPress Protocol: http://jiia.org/wp-content/themes/jiia/pdf/standard_dl/coaxpress/CXP-001-2021.pdf
-------------------------------------------------------------------------------
-- Company    : SLAC National Accelerator Laboratory
-------------------------------------------------------------------------------
-- Description: CoaXPress Transmit
-------------------------------------------------------------------------------
-- This file is part of 'SLAC Firmware Standard Library'.
-- It is subject to the license terms in the LICENSE.txt file found in the
-- top-level directory of this distribution and at:
--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
-- No part of 'SLAC Firmware Standard Library', including this file,
-- may be copied, modified, propagated, or distributed except according to
-- the terms contained in the LICENSE.txt file.
-------------------------------------------------------------------------------

library ieee;
use ieee.std_logic_1164.all;
use ieee.std_logic_unsigned.all;
use ieee.std_logic_arith.all;

library surf;
use surf.StdRtlPkg.all;
use surf.AxiStreamPkg.all;
use surf.CoaXPressPkg.all;
use surf.SsiPkg.all;

entity CoaXPressTx is
   generic (
      TPD_G : time := 1 ns);
   port (
      -- Config Interface (cfgClk domain)
      cfgClk       : in  sl;
      cfgRst       : in  sl;
      cfgTxMaster  : in  AxiStreamMasterType;
      cfgTxSlave   : out AxiStreamSlaveType;
      -- Event ACK Interface (cfgClk domain)
      eventAck     : in  sl;
      eventTag     : in  slv(7 downto 0);
      -- TX PHY Interface (txClk domain)
      txClk        : in  sl;
      txRst        : in  sl;
      txLsRate     : in  sl;
      txLsValid    : out sl;
      txLsData     : out slv(7 downto 0);
      txLsDataK    : out sl;
      -- Trigger Interface (txClk domain)
      txTrigInv    : in  sl;
      txPulseWidth : in  slv(31 downto 0);
      swTrig       : in  sl;
      txTrig       : in  sl;
      txTrigDrop   : out sl);
end entity CoaXPressTx;

architecture mapping of CoaXPressTx is

   signal eventAckMaster : AxiStreamMasterType;
   signal eventAckSlave  : AxiStreamSlaveType;

   signal txMaster : AxiStreamMasterType;
   signal txSlave  : AxiStreamSlaveType;

   signal cfgMaster : AxiStreamMasterType;
   signal cfgSlave  : AxiStreamSlaveType;

   signal trigger : sl;
   signal txIndex : slv(1 downto 0);

begin

   U_EventAckMsg : entity surf.CoaXPressEventAckMsg
      generic map (
         TPD_G => TPD_G)
      port map (
         -- Clock and Reset
         clk            => cfgClk,
         rst            => cfgRst,
         -- Event ACK Interface
         eventAck       => eventAck,
         eventTag       => eventTag,
         -- AXI Stream Interface
         eventAckMaster => eventAckMaster,
         eventAckSlave  => eventAckSlave);

   U_Mux : entity surf.AxiStreamMux
      generic map (
         TPD_G         => TPD_G,
         NUM_SLAVES_G  => 2,
         PIPE_STAGES_G => 1)
      port map (
         -- Clock and reset
         axisClk         => cfgClk,
         axisRst         => cfgRst,
         -- Slaves
         sAxisMasters(0) => cfgTxMaster,
         sAxisMasters(1) => eventAckMaster,
         sAxisSlaves(0)  => cfgTxSlave,
         sAxisSlaves(1)  => eventAckSlave,
         -- Master
         mAxisMaster     => txMaster,
         mAxisSlave      => txSlave);

   U_LsFifo : entity surf.AxiStreamFifoV2
      generic map (
         -- General Configurations
         TPD_G               => TPD_G,
         VALID_THOLD_G       => 0,      -- 0 = store/forward AXIS FIFO
         -- FIFO configurations
         MEMORY_TYPE_G       => "block",
         GEN_SYNC_FIFO_G     => false,
         FIFO_ADDR_WIDTH_G   => 9,
         -- AXI Stream Port Configurations
         SLAVE_AXI_CONFIG_G  => ssiAxiStreamConfig(dataBytes => 1),  -- 8-bit interface
         MASTER_AXI_CONFIG_G => ssiAxiStreamConfig(dataBytes => 1))  -- 8-bit interface
      port map (
         -- Slave Port
         sAxisClk    => cfgClk,
         sAxisRst    => cfgRst,
         sAxisMaster => txMaster,
         sAxisSlave  => txSlave,
         -- Master Port
         mAxisClk    => txClk,
         mAxisRst    => txRst,
         mAxisMaster => cfgMaster,
